      <section class="tab-content" id="pos-tab" data-screen-label="POS">
        <div class="pos-wrap">
          <div class="pos-left">
            <div class="pos-toolbar">
              <div class="pos-search">
                <i class="fa-solid fa-magnifying-glass"></i>
                <input id="pos-search-input" placeholder="Search menu…">
                <div class="mobile-only-inline pos-m-hold-buttons" id="pos-m-hold-buttons" style="display:none; align-items:center; gap:4px;">
                  <button class="hold-btn hold-btn-takeaway" id="btn-m-hold-takeaway" style="padding: 4px 8px; font-size: 11px;">
                    <i class="fa-solid fa-bag-shopping"></i> <span id="held-count-takeaway-m"></span>
                  </button>
                  <button class="hold-btn hold-btn-dinein" id="btn-m-hold-dinein" style="padding: 4px 8px; font-size: 11px;">
                    <i class="fa-solid fa-utensils"></i> <span id="held-count-dinein-m"></span>
                  </button>
                  <button class="hold-btn hold-btn-delivery" id="btn-m-hold-delivery" style="padding: 4px 8px; font-size: 11px;">
                    <i class="fa-solid fa-motorcycle"></i> <span id="held-count-delivery-m"></span>
                  </button>
                </div>
              </div>
              <div class="pos-sort custom-dropdown-widget" id="pos-sort-widget">
                <div class="dropdown-trigger" id="pos-sort-trigger" tabindex="0" role="button" aria-haspopup="listbox" aria-expanded="false" aria-label="Sort Menu Items">
                  <span id="pos-sort-trigger-text">Most Ordered</span>
                  <i class="fa-solid fa-chevron-down caret"></i>
                </div>
                <ul class="dropdown-menu" id="pos-sort-menu" role="listbox">
                  <li class="dropdown-item active" data-value="popular" role="option" aria-selected="true">Most Ordered</li>
                  <li class="dropdown-item" data-value="default" role="option" aria-selected="false">Default Order</li>
                  <li class="dropdown-item" data-value="name-asc" role="option" aria-selected="false">Alphabetical: A-Z</li>
                  <li class="dropdown-item" data-value="name-desc" role="option" aria-selected="false">Alphabetical: Z-A</li>
                  <li class="dropdown-item" data-value="price-asc" role="option" aria-selected="false">Price: Low to High</li>
                  <li class="dropdown-item" data-value="price-desc" role="option" aria-selected="false">Price: High to Low</li>
                  <li class="dropdown-item" data-value="veg-first" role="option" aria-selected="false">Veg First</li>
                  <li class="dropdown-item" data-value="nonveg-first" role="option" aria-selected="false">Non-Veg First</li>
                </ul>
                <select id="pos-sort-select" class="pos-sort-select" style="display: none;">
                  <option value="popular">Most Ordered</option>
                  <option value="default">Default Order</option>
                  <option value="name-asc">Alphabetical: A-Z</option>
                  <option value="name-desc">Alphabetical: Z-A</option>
                  <option value="price-asc">Price: Low to High</option>
                  <option value="price-desc">Price: High to Low</option>
                  <option value="veg-first">Veg First</option>
                  <option value="nonveg-first">Non-Veg First</option>
                </select>
              </div>
              <div class="pos-size-control">
                <button id="btn-grid-dec" title="Decrease item size"><i class="fa-solid fa-minus"></i></button>
                <input type="range" id="pos-grid-slider" min="110" max="250" value="158" title="Adjust item size">
                <button id="btn-grid-inc" title="Increase item size"><i class="fa-solid fa-plus"></i></button>
              </div>
              <div class="order-types" id="pos-menu-order-types">
                <button class="order-type-btn active"><i class="fa-solid fa-bag-shopping"></i> Takeaway</button>
                <button class="order-type-btn"><i class="fa-solid fa-utensils"></i> Dine-in</button>
                <button class="order-type-btn"><i class="fa-solid fa-motorcycle"></i> Delivery</button>
              </div>
            </div>
            <!-- Active Table Status Banner (Dine-in Only) -->
            <div class="pos-active-table-banner" id="pos-active-table-banner" style="display: none; align-items: center; justify-content: space-between; padding: 10px 14px; margin: 0 10px 14px 10px; background: var(--orange-tint); border: 1px dashed rgba(255,107,0,0.35); border-radius: var(--r-sm);">
              <div style="display: flex; align-items: center; gap: 8px; font-size: 13px; font-weight: 700; color: var(--text);">
                <span class="table-status-dot" id="pos-banner-status-dot" style="width: 8px; height: 8px; border-radius: 50%; background: var(--green);"></span>
                <span id="pos-banner-text">Active Table: None</span>
              </div>
              <button type="button" class="btn btn-sm btn-ghost" id="btn-change-table" style="color: var(--orange); font-weight: 700; font-size: 11px; padding: 4px 8px; height: 26px; border: 1px solid rgba(255,107,0,0.25);">
                <i class="fa-solid fa-chair"></i> Change Table
              </button>
            </div>
            <div class="pos-cats" id="pos-cats"></div>
            <div class="pos-grid" id="pos-grid"></div>
            <!-- Interactive Seating Layout Selections Grid -->
            <div class="pos-table-grid-view" id="pos-table-grid-view" style="display: none; padding: 0 12px 20px 12px;">
              <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 14px;">
                <h3 style="font-size: 14px; font-weight: 700; color: var(--text);">POS Seating Layout - Select Table</h3>
                <div style="display: flex; gap: 12px; font-size: 11px; color: var(--text-soft); font-weight: 600;">
                  <span style="display: flex; align-items: center; gap: 4px;"><span style="width: 8px; height: 8px; border-radius: 50%; background: var(--green);"></span> Free</span>
                  <span style="display: flex; align-items: center; gap: 4px;"><span style="width: 8px; height: 8px; border-radius: 50%; background: var(--orange);"></span> Occupied</span>
                  <span style="display: flex; align-items: center; gap: 4px;"><span style="width: 8px; height: 8px; border-radius: 50%; background: var(--violet-soft);"></span> Billed</span>
                </div>
              </div>
              <div class="pos-tables-grid" id="pos-tables-grid" style="display: grid; grid-template-columns: repeat(auto-fill, minmax(130px, 1fr)); gap: 12px;">
                <!-- Tables rendered by JS -->
              </div>
            </div>
          </div>

          <aside class="pos-cart">
            <div class="cart-head">
              <button class="btn btn-ghost btn-sm mobile-only-inline" id="btn-pos-back-menu" style="margin-right:8px; padding: 4px 8px; font-size:12px; font-weight:600;"><i class="fa-solid fa-chevron-left"></i> Back</button>
              <h3>Current Order</h3>
              <div style="display:flex; align-items:center; gap:6px;">
                <span class="pill pill-orange" style="padding:4px 11px"><span id="cart-count">0 items</span></span>
                <button class="btn btn-ghost" id="btn-clear-cart" title="Clear Cart" style="padding:4px 6px; color:var(--orange); font-size:12px; height:24px; display:inline-flex; align-items:center; justify-content:center;"><i class="fa-solid fa-trash-can"></i></button>
              </div>
            </div>
            <div class="order-types cart-order-types" id="pos-cart-order-types">
              <button class="order-type-btn active"><i class="fa-solid fa-bag-shopping"></i> Takeaway</button>
              <button class="order-type-btn"><i class="fa-solid fa-utensils"></i> Dine-in</button>
              <button class="order-type-btn"><i class="fa-solid fa-motorcycle"></i> Delivery</button>
            </div>
            <div class="cart-table-sel" style="display: grid; grid-template-columns: 1fr 1fr; gap: 8px; position: relative;">
              <select class="form-input" id="cart-table"><option>Walk-in / Takeaway</option><option>Table 01</option><option>Table 02</option><option>Table 04</option><option>Table 08</option></select>
              <div class="custom-customer-widget" id="custom-customer-widget">
                <div class="cust-widget-trigger" id="cust-widget-trigger" tabindex="0" role="button" aria-haspopup="true" aria-expanded="false" aria-label="Customer Selector">
                  <i class="fa-solid fa-user-tag"></i>
                  <span id="cust-trigger-text">Walk-in</span>
                  <i class="fa-solid fa-chevron-down caret"></i>
                </div>
                <div class="cust-widget-dropdown" id="cust-widget-dropdown">
                  <div class="cust-fields-row">
                    <div class="field-group">
                      <label>Name</label>
                      <input type="text" id="cust-input-name" placeholder="John Doe" autocomplete="off" class="form-input">
                    </div>
                    <div class="field-group">
                      <label>Phone</label>
                      <input type="text" id="cust-input-phone" placeholder="9876543210" autocomplete="off" class="form-input">
                    </div>
                  </div>
                  
                  <div class="cust-search-results" id="cust-search-results" style="display: none;"></div>
                  
                  <div class="cust-insights-panel" id="cust-insights-panel" style="display: none;">
                    <div class="insight-item">
                      <span class="insight-label">Visits</span>
                      <span class="insight-val" id="insight-visits">0</span>
                    </div>
                    <div class="insight-item">
                      <span class="insight-label">Spent</span>
                      <span class="insight-val" id="insight-spend">₹0</span>
                    </div>
                    <div class="insight-item" style="grid-column: span 2; border-top: 1px solid var(--stroke); padding-top: 4px; margin-top: 4px;">
                      <span class="insight-label">Favorite</span>
                      <span class="insight-val" id="insight-favorite">None</span>
                    </div>
                  </div>

                  <div class="cust-action-row" id="cust-action-row" style="display: none; margin-top: 6px;">
                    <button type="button" class="btn btn-sm btn-primary" id="btn-save-new-cust" style="width: 100%; justify-content: center; font-size:11px; padding: 6px 8px;">
                      <i class="fa-solid fa-plus"></i> Add New Customer
                    </button>
                  </div>
                  
                  <div class="cust-reset-row" style="margin-top: 6px; border-top: 1px solid var(--stroke); padding-top: 6px;">
                    <button type="button" class="btn btn-sm btn-ghost" id="btn-reset-cust" style="width: 100%; justify-content: center; font-size:11px; color: var(--text-soft); padding: 6px 8px;">
                      <i class="fa-solid fa-user-slash"></i> Reset to Walk-in
                    </button>
                  </div>
                </div>
              </div>
              <select class="form-input" id="cart-customer-sel" style="display: none;"><option value="">Walk-in Customer</option></select>
            </div>
            <!-- Delivery Details Row (hidden by default) -->
            <div class="cart-delivery-details" id="cart-delivery-details" style="display: none; flex-direction: column; gap: 6px; margin-top: 8px; padding: 10px; background: var(--glass-2); border: 1px solid var(--stroke-2); border-radius: var(--r-sm);">
              <div style="font-size: 10px; font-weight: 700; text-transform: uppercase; color: var(--text-soft); letter-spacing: 0.05em; display: flex; align-items: center; gap: 4px;">
                <i class="fa-solid fa-truck-ramp-box"></i> Delivery Details
              </div>
              <div style="display: flex; gap: 6px;">
                <input type="text" id="delivery-address" placeholder="Delivery Address" class="form-input" style="flex: 2; height: 32px; font-size: 12px; padding: 6px 8px;">
                <input type="number" id="delivery-charge" placeholder="Charge" class="form-input" style="flex: 1; height: 32px; font-size: 12px; padding: 6px 8px;" min="0">
              </div>
              <input type="text" id="delivery-rider" placeholder="Rider Name / Notes" class="form-input" style="width: 100%; height: 32px; font-size: 12px; padding: 6px 8px;">
            </div>
            <div class="cart-items" id="cart-items"></div>
            <div class="cart-foot">
              <div class="totals">
                <div class="tr"><span>Subtotal</span><b id="t-sub">₹0</b></div>
                <div class="tr grand"><span class="lbl">Total</span><span class="amt" id="t-grand">₹0</span></div>
              </div>
              <div class="cart-payment" id="cart-payment" style="margin-top: 6px; padding: 6px; border: 1px solid var(--stroke-2); border-radius: var(--r-sm); background: var(--glass-1);">
                <div class="cpay-methods" id="cart-pay-methods" style="display: grid; grid-template-columns: repeat(5, 1fr); gap: 4px;">
                  <button type="button" class="active" data-pay-method="Cash" style="min-height: 38px; padding: 4px 2px; font-size: 11px; font-weight: 700; display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 2px;">
                    <i class="fa-solid fa-money-bill-wave" style="font-size: 12px; color: #25d366;"></i>
                    <span>Cash</span>
                  </button>
                  <button type="button" data-pay-method="UPI" style="min-height: 38px; padding: 4px 2px; font-size: 11px; font-weight: 700; display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 2px;">
                    <i class="fa-solid fa-qrcode" style="font-size: 12px; color: var(--orange);"></i>
                    <span>UPI</span>
                  </button>
                  <button type="button" data-pay-method="Card" style="min-height: 38px; padding: 4px 2px; font-size: 11px; font-weight: 700; display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 2px;">
                    <i class="fa-solid fa-credit-card" style="font-size: 12px; color: #1e90ff;"></i>
                    <span>Card</span>
                  </button>
                  <button type="button" data-pay-method="Due" style="min-height: 38px; padding: 4px 2px; font-size: 11px; font-weight: 700; display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 2px;">
                    <i class="fa-solid fa-clock-rotate-left" style="font-size: 12px; color: var(--red);"></i>
                    <span>Due</span>
                  </button>
                  <button type="button" data-pay-method="Split" style="min-height: 38px; padding: 4px 2px; font-size: 11px; font-weight: 700; display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 2px;">
                    <i class="fa-solid fa-arrows-split-up-and-left" style="font-size: 12px; color: #9c27b0;"></i>
                    <span>Split</span>
                  </button>
                </div>

                <!-- Horizontal Cash Calculator Drawer -->
                <div id="cash-calc-inline" style="display: none; align-items: center; gap: 6px; margin-top: 6px; padding-top: 6px; border-top: 1px dashed var(--stroke-2); justify-content: space-between; overflow-x: auto; width: 100%;">
                  <div style="display: flex; align-items: center; gap: 4px; flex-shrink: 0;">
                    <i class="fa-solid fa-money-bill-wave" style="color: #25d366; font-size: 11px;"></i>
                    <span style="font-size: 9px; font-weight: 800; color: var(--text-soft); text-transform: uppercase; white-space: nowrap;">Cash</span>
                    <button type="button" class="btn-popover-close" style="background: none; border: none; font-size: 14px; font-weight: 700; color: var(--text-soft); cursor: pointer; padding: 0 2px; line-height: 1;">&times;</button>
                  </div>
                  <div style="display: flex; align-items: center; gap: 4px; flex-shrink: 0;">
                    <span style="font-size: 9px; font-weight: 700; color: var(--text-soft);">Recv:</span>
                    <input type="number" id="inline-cash-received" class="form-input" style="width: 55px; height: 22px; padding: 2px 4px; font-size: 11px; font-weight: 700; text-align: right; margin: 0; border-radius: 4px;">
                  </div>
                  <div style="font-size: 9px; font-weight: 700; color: var(--text-soft); display: flex; align-items: center; gap: 2px; flex-shrink: 0;">
                    <span>Change:</span>
                    <strong id="inline-cash-change" style="color: #25d366; font-size: 11px;">₹0</strong>
                  </div>
                  <!-- Scrollable/wrapped denominations row -->
                  <div id="cash-denominations-grid" style="display: flex; gap: 3px; flex-shrink: 0; overflow-x: auto; padding: 2px 0;">
                    <button type="button" class="btn-den" data-val="exact" style="height: 20px; min-width: 24px; font-size: 9px; font-weight: 700; padding: 0 4px; border: 1px solid var(--orange); color: var(--orange); background: transparent; border-radius: 4px; cursor: pointer;">Ex</button>
                    <button type="button" class="btn-den" data-val="10" style="height: 20px; min-width: 24px; font-size: 9px; font-weight: 700; padding: 0 4px; border: 1px solid var(--stroke-2); color: var(--text-soft); background: var(--glass-2); border-radius: 4px; cursor: pointer;">10</button>
                    <button type="button" class="btn-den" data-val="20" style="height: 20px; min-width: 24px; font-size: 9px; font-weight: 700; padding: 0 4px; border: 1px solid var(--stroke-2); color: var(--text-soft); background: var(--glass-2); border-radius: 4px; cursor: pointer;">20</button>
                    <button type="button" class="btn-den" data-val="50" style="height: 20px; min-width: 24px; font-size: 9px; font-weight: 700; padding: 0 4px; border: 1px solid var(--stroke-2); color: var(--text-soft); background: var(--glass-2); border-radius: 4px; cursor: pointer;">50</button>
                    <button type="button" class="btn-den" data-val="100" style="height: 20px; min-width: 24px; font-size: 9px; font-weight: 700; padding: 0 4px; border: 1px solid var(--stroke-2); color: var(--text-soft); background: var(--glass-2); border-radius: 4px; cursor: pointer;">100</button>
                    <button type="button" class="btn-den" data-val="200" style="height: 20px; min-width: 24px; font-size: 9px; font-weight: 700; padding: 0 4px; border: 1px solid var(--stroke-2); color: var(--text-soft); background: var(--glass-2); border-radius: 4px; cursor: pointer;">200</button>
                    <button type="button" class="btn-den" data-val="500" style="height: 20px; min-width: 24px; font-size: 9px; font-weight: 700; padding: 0 4px; border: 1px solid var(--stroke-2); color: var(--text-soft); background: var(--glass-2); border-radius: 4px; cursor: pointer;">500</button>
                    <button type="button" class="btn-den" data-val="2000" style="height: 20px; min-width: 24px; font-size: 9px; font-weight: 700; padding: 0 4px; border: 1px solid var(--stroke-2); color: var(--text-soft); background: var(--glass-2); border-radius: 4px; cursor: pointer;">2k</button>
                    <button type="button" class="btn-den" data-val="clear" style="height: 20px; min-width: 24px; font-size: 9px; font-weight: 700; padding: 0 4px; border: 1px solid var(--red); color: var(--red); background: transparent; border-radius: 4px; cursor: pointer;">C</button>
                  </div>
                </div>

                <!-- Horizontal Split Calculator Drawer -->
                <div id="split-calc-compact" style="display: none; align-items: center; gap: 6px; margin-top: 6px; padding-top: 6px; border-top: 1px dashed var(--stroke-2); justify-content: space-between; overflow-x: auto; width: 100%;">
                  <div style="display: flex; align-items: center; gap: 4px; flex-shrink: 0;">
                    <i class="fa-solid fa-arrows-split-up-and-left" style="color: #9c27b0; font-size: 11px;"></i>
                    <span style="font-size: 9px; font-weight: 800; color: var(--text-soft); text-transform: uppercase; white-space: nowrap;">Split</span>
                    <button type="button" class="btn-popover-close" style="background: none; border: none; font-size: 14px; font-weight: 700; color: var(--text-soft); cursor: pointer; padding: 0 2px; line-height: 1;">&times;</button>
                  </div>
                  <div style="display: flex; gap: 4px; align-items: center; flex: 1; overflow-x: auto; padding: 2px 0;">
                    <div style="display: flex; align-items: center; gap: 3px; border: 1px solid var(--stroke-2); padding: 2px 4px; border-radius: 4px; background: var(--panel); min-width: 60px;">
                      <i class="fa-solid fa-money-bill-wave" style="font-size: 9px; color: #25d366;" title="Cash"></i>
                      <input type="number" id="split-cash" placeholder="Cash" class="form-input" style="border: none; background: transparent; height: 18px; font-size: 10px; font-weight: 700; padding: 0; margin: 0; width: 100%; text-align: right;">
                    </div>
                    <div style="display: flex; align-items: center; gap: 3px; border: 1px solid var(--stroke-2); padding: 2px 4px; border-radius: 4px; background: var(--panel); min-width: 60px;">
                      <i class="fa-solid fa-qrcode" style="font-size: 9px; color: var(--orange);" title="UPI"></i>
                      <input type="number" id="split-upi" placeholder="UPI" class="form-input" style="border: none; background: transparent; height: 18px; font-size: 10px; font-weight: 700; padding: 0; margin: 0; width: 100%; text-align: right;">
                    </div>
                    <div style="display: flex; align-items: center; gap: 3px; border: 1px solid var(--stroke-2); padding: 2px 4px; border-radius: 4px; background: var(--panel); min-width: 60px;">
                      <i class="fa-solid fa-credit-card" style="font-size: 9px; color: #1e90ff;" title="Card"></i>
                      <input type="number" id="split-card" placeholder="Card" class="form-input" style="border: none; background: transparent; height: 18px; font-size: 10px; font-weight: 700; padding: 0; margin: 0; width: 100%; text-align: right;">
                    </div>
                    <div style="display: flex; align-items: center; gap: 3px; border: 1px solid var(--stroke-2); padding: 2px 4px; border-radius: 4px; background: var(--panel); min-width: 60px;">
                      <i class="fa-solid fa-clock-rotate-left" style="font-size: 9px; color: var(--red);" title="Due"></i>
                      <input type="number" id="split-due" placeholder="Due" class="form-input" style="border: none; background: transparent; height: 18px; font-size: 10px; font-weight: 700; padding: 0; margin: 0; width: 100%; text-align: right;">
                    </div>
                  </div>
                  <div style="display: flex; flex-direction: column; align-items: flex-end; font-size: 9px; line-height: 1.1; flex-shrink: 0;">
                    <span id="split-status-text" style="font-weight: 700; color: var(--text-soft); white-space: nowrap;">Remaining: ₹0</span>
                    <strong id="split-total-text" style="font-weight: 800; color: var(--orange); white-space: nowrap;">Paid: ₹0</strong>
                  </div>
                </div>
              </div>
              <div class="cart-actions" style="margin-top: 6px;">
                <div class="hold-buttons-group">
                  <button class="hold-btn hold-btn-takeaway" id="btn-hold-takeaway"><i class="fa-solid fa-bag-shopping"></i> Hold <span id="held-count-takeaway"></span></button>
                  <button class="hold-btn hold-btn-dinein" id="btn-hold-dinein" style="display:none;"><i class="fa-solid fa-utensils"></i> Hold <span id="held-count-dinein"></span></button>
                  <button class="hold-btn hold-btn-delivery" id="btn-hold-delivery" style="display:none;"><i class="fa-solid fa-motorcycle"></i> Hold <span id="held-count-delivery"></span></button>
                </div>
                <button class="btn btn-ghost" id="btn-kot"><i class="fa-solid fa-fire"></i> Send KOT</button>
                <button class="btn btn-primary" id="btn-checkout" style="grid-column:1 / -1; font-weight:700;"><i class="fa-solid fa-print"></i> Print &amp; Pay</button>
              </div>
            </div>
          </aside>
        </div>
      </section>

      <!-- ============ QR ORDERS ============ -->
      <section class="tab-content" id="qr-orders-tab" data-screen-label="QR Orders">
        <div class="stat-row">
          <div class="stat-card"><div class="stat-ic bg-a"><i class="fa-solid fa-hourglass-half"></i></div><div><div class="sv">0</div><div class="sl">Pending accept</div></div></div>
          <div class="stat-card"><div class="stat-ic bg-o"><i class="fa-solid fa-fire-burner"></i></div><div><div class="sv">0</div><div class="sl">Preparing</div></div></div>
          <div class="stat-card"><div class="stat-ic bg-g"><i class="fa-solid fa-circle-check"></i></div><div><div class="sv">0</div><div class="sl">Served</div></div></div>
          <div class="stat-card"><div class="stat-ic bg-v"><i class="fa-solid fa-table"></i></div><div><div class="sv">0 / 12</div><div class="sl">Tables occupied</div></div></div>
        </div>
        <div class="qr-grid" id="qr-grid"></div>
