          const tenantId = document.getElementById('manage-tenant-id').value;
          const tenantName = document.getElementById('manage-tenant-name').textContent;

          if (confirm(`Are you absolutely sure you want to DELETE: ${tenantName}?

This will permanently erase their registration and cascade delete all their data!`)) {
