        const revenue = slice.reduce((s, d) => s + d.revenue, 0);
        const orders  = slice.reduce((s, d) => s + d.orders, 0);
        byWeek.push({
          week_start:      slice[0]?.date || "",
          week_end:        slice[slice.length - 1]?.date || "",
          revenue,
          orders,
          avg_order_value: orders ? revenue / orders : 0
        });
      }
      return byWeek;
