    // ── Revenue: Monthly ──────────────────────────────────────────────────────

    async function monthlyRevenue({ months = 6 } = {}) {
      const bills  = await fetchBills(daysAgo(months * 31));
      const byMonth = groupBy(bills, (b) => b.created_at.slice(0, 7)); // "YYYY-MM"
      const result = [];
      for (let m = months - 1; m >= 0; m--) {
