    async function itemPopularity({ days = 30, limit = 20 } = {}) {
      const bills = await fetchBills(daysAgo(days));
      const map   = new Map();

      bills.forEach((bill) => {
        const items = safeJsonArray(bill.items);
        items.forEach((item) => {
