.app.collapsed .sb-foot-btn span { display: none; }

/* ===================== MAIN ===================== */
.main { display: flex; flex-direction: column; min-height: 100vh; min-width: 0; }
.topbar { position: sticky; top: 0; display: flex; align-items: center; gap: 16px; padding: 14px clamp(16px,2.4vw,28px); border-bottom: 1px solid var(--stroke); background: var(--panel); -webkit-backdrop-filter: blur(20px) saturate(150%); backdrop-filter: blur(20px) saturate(150%); z-index: 20; }
.tb-title { flex: none; }
.tb-title h1 { font-size: 21px; letter-spacing: -0.02em; white-space: nowrap; }
.tb-title p { font-size: 12.5px; color: var(--text-mute); }
.tb-spacer { flex: 1; }
.tb-search { display: flex; align-items: center; gap: 9px; padding: 9px 14px; border-radius: var(--r-pill); background: var(--glass); border: 1px solid var(--stroke-2); width: 240px; transition: var(--t); }
.tb-search:focus-within { border-color: var(--orange); width: 280px; }
.tb-search i { color: var(--text-mute); font-size: 13px; }
.tb-search input { border: none; background: none; outline: none; color: var(--text); font-family: var(--font-body); font-size: 13.5px; width: 100%; }
.tb-search input::placeholder { color: var(--text-faint); }
.tb-pill { display: inline-flex; align-items: center; gap: 8px; padding: 8px 13px; border-radius: var(--r-pill); background: var(--glass); border: 1px solid var(--stroke-2); font-size: 12.5px; font-weight: 600; color: var(--text-soft); transition: var(--t); cursor: default; }
.tb-pill.sync { color: var(--green); border-color: oklch(0.74 0.15 158 / 0.3); background: var(--green-tint); }
.tb-icon-btn { width: 40px; height: 40px; border-radius: 50%; border: 1px solid var(--stroke-2); background: var(--glass); color: var(--text-soft); display: grid; place-items: center; cursor: pointer; transition: var(--t); position: relative; }
.tb-icon-btn:hover { color: var(--text); border-color: var(--stroke-hi); transform: translateY(-1px); }
.tb-icon-btn .dot-notif { position: absolute; top: 8px; right: 9px; width: 8px; height: 8px; border-radius: 50%; background: var(--orange); border: 2px solid var(--panel-solid); }
@media (max-width: 1100px){ .tb-search{display:none;} }
@media (max-width: 860px){ .tb-pill.txt{display:none;} }

.content { flex: 1; padding: clamp(16px,2.4vw,28px); position: relative; min-width: 0; }
.tab-content { display: none; min-width: 0; }
.tab-content.active { display: block; }

/* generic panel */
.panel { border-radius: var(--r-lg); background: var(--panel); border: 1px solid var(--stroke); -webkit-backdrop-filter: blur(16px); backdrop-filter: blur(16px); min-width: 0; }
.table-scroll { overflow-x: auto; max-width: 100%; }
.panel-pad { padding: 20px; }
.panel-head { display: flex; align-items: center; justify-content: space-between; gap: 12px; margin-bottom: 16px; }
.panel-head h3 { font-size: 16px; }
.panel-head .ph-sub { font-size: 12px; color: var(--text-mute); }

/* stat cards row */
.stat-row { display: grid; grid-template-columns: repeat(4,1fr); gap: 14px; margin-bottom: 18px; }
.stat-card { border-radius: var(--r-md); padding: 17px; background: var(--panel); border: 1px solid var(--stroke); display: flex; gap: 13px; align-items: center; transition: var(--t); }
.stat-card:hover { transform: translateY(-3px); border-color: var(--stroke-hi); box-shadow: var(--shadow-md); }
.stat-ic { width: 44px; height: 44px; border-radius: 13px; display: grid; place-items: center; font-size: 17px; flex: none; }
.stat-card .sv { font-family: var(--font-display); font-weight: 800; font-size: 23px; letter-spacing: -0.02em; line-height: 1; }
.stat-card .sl { font-size: 12px; color: var(--text-mute); margin-top: 4px; }
.stat-card .sd { font-size: 11px; font-weight: 700; margin-top: 4px; }
.up { color: var(--green); } .down { color: var(--red); }
.bg-o { background: var(--orange-tint); color: var(--orange); }
.bg-v { background: var(--violet-tint); color: var(--violet-soft); }
.bg-g { background: var(--green-tint); color: var(--green); }
.bg-t { background: oklch(0.74 0.12 200 / 0.16); color: var(--teal); }
.bg-a { background: var(--amber-tint); color: var(--amber); }
.bg-r { background: var(--red-tint); color: var(--red); }
@media (max-width: 980px){ .stat-row{grid-template-columns:repeat(2,1fr);} }

/* ===================== POS ===================== */
.pos-wrap { display: grid; grid-template-columns: 1fr 372px; gap: 16px; align-items: start; }
.pos-left { display: flex; flex-direction: column; gap: 14px; }
.pos-toolbar { display: flex; gap: 12px; align-items: center; }
.pos-search { flex: 1; display: flex; align-items: center; gap: 10px; padding: 11px 16px; border-radius: var(--r-pill); background: var(--panel); border: 1px solid var(--stroke-2); }
.pos-search i { color: var(--text-mute); }
.pos-search input { border: none; background: none; outline: none; color: var(--text); font-family: var(--font-body); font-size: 14px; width: 100%; }
.order-types { display: flex; gap: 8px; }
.order-type-btn { padding: 11px 16px; border-radius: var(--r-pill); border: 1px solid var(--stroke-2); background: var(--panel); color: var(--text-soft); font-size: 13px; font-weight: 600; cursor: pointer; transition: var(--t); display: inline-flex; align-items: center; gap: 7px; }
.order-type-btn.active { background: var(--orange-tint); color: var(--orange); border-color: rgba(255,79,0,0.35); }
.pos-cats { display: flex; gap: 8px; overflow-x: auto; padding-bottom: 4px; }
.pos-cats::-webkit-scrollbar { height: 5px; }
.pos-cat-btn { padding: 8px 15px; border-radius: var(--r-pill); border: 1px solid var(--stroke-2); background: var(--panel); color: var(--text-soft); font-size: 13px; font-weight: 600; cursor: pointer; white-space: nowrap; transition: var(--t); display: inline-flex; align-items: center; gap: 7px; }
.pos-cat-btn:hover { border-color: var(--stroke-hi); color: var(--text); }
.pos-cat-btn.active { background: linear-gradient(135deg,var(--orange-soft),var(--orange-deep)); color: #fff; border-color: transparent; box-shadow: var(--glow-orange); }
.pos-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(var(--pos-grid-size, 158px), 1fr)); gap: 13px; padding: 2px; align-content: start; }
.pos-size-control { display: flex; align-items: center; gap: 8px; background: var(--panel); border: 1px solid var(--stroke-2); padding: 5px 12px; border-radius: var(--r-pill); height: 38px; box-sizing: border-box; }
.pos-size-control button { background: none; border: none; color: var(--text-soft); cursor: pointer; padding: 4px; display: flex; align-items: center; justify-content: center; transition: color .2s, transform .1s; outline: none; }
.pos-size-control button:hover { color: var(--text); transform: scale(1.15); }
.pos-size-control button:active { transform: scale(0.9); }
.pos-size-control input[type="range"] { width: 80px; accent-color: var(--orange); cursor: pointer; height: 4px; outline: none; }
.pos-item { border-radius: var(--r-md); background: var(--panel); border: 1px solid var(--stroke); padding: clamp(6px, calc((8 * var(--pos-grid-size, 158px) - 592px) / 48), 22px) clamp(7px, calc((8 * var(--pos-grid-size, 158px) - 544px) / 48), 24px) clamp(5px, calc((8 * var(--pos-grid-size, 158px) - 640px) / 48), 20px); cursor: pointer; transition: transform .22s var(--ease), border-color .2s, box-shadow .3s, background .2s; position: relative; overflow: hidden; display: flex; flex-direction: column; gap: clamp(4px, calc((7 * var(--pos-grid-size, 158px) - 578px) / 48), 16px); min-height: calc(var(--pos-grid-size, 158px) * 0.772); aspect-ratio: 158 / 122; }
.pos-item::before { content: ""; position: absolute; left: 0; top: 0; bottom: 0; width: 3px; background: var(--cc, var(--orange)); opacity: .9; }
.pos-item::after { content: ""; position: absolute; inset: 0; pointer-events: none; background: radial-gradient(130% 100% at 0% 0%, color-mix(in srgb, var(--cc, var(--orange)) 10%, transparent), transparent 58%); }
.pos-item:hover { transform: translateY(-4px); border-color: color-mix(in srgb, var(--cc, var(--orange)) 55%, transparent); box-shadow: var(--shadow-md); }
.pos-item:active { transform: translateY(-1px) scale(.98); }
.pos-item > * { position: relative; z-index: 1; }
.pos-item .pi-top { display: flex; align-items: center; gap: clamp(4px, calc(8 * var(--pos-grid-size, 158px) / 158), 12px); }
.pos-item .picat { font-size: clamp(8px, calc(9.5 * var(--pos-grid-size, 158px) / 158), 13px); font-weight: 700; letter-spacing: .13em; text-transform: uppercase; color: var(--cc, var(--text-mute)); }
[data-theme="light"] .pos-item .picat { color: color-mix(in srgb, var(--cc, var(--text-mute)) 58%, #000); }
.pos-item .pname { font-family: var(--font-display); font-weight: 700; font-size: clamp(10.5px, calc((9 * var(--pos-grid-size, 158px) + 18px) / 96), 22px); line-height: 1.18; letter-spacing: -.01em; flex: 1; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }
.pos-item .prow { display: flex; align-items: center; justify-content: space-between; }
.pos-item .pprice { font-family: var(--font-display); font-weight: 800; font-size: clamp(12px, calc(var(--pos-grid-size, 158px) / 8 - 1.75px), 26px); letter-spacing: -.02em; color: var(--text); }
.stock-dot { font-size: 10.5px; font-weight: 700; padding: 2px 8px; border-radius: 99px; }
.pos-item .stock-dot { font-size: clamp(8.5px, calc(10.5 * var(--pos-grid-size, 158px) / 158), 15px); padding: clamp(1px, calc(2 * var(--pos-grid-size, 158px) / 158), 4px) clamp(5px, calc(8 * var(--pos-grid-size, 158px) / 158), 12px); }
.stock-ok { background: var(--green-tint); color: var(--green); }
.stock-low { background: var(--amber-tint); color: var(--amber); }
.stock-out { background: var(--red-tint); color: var(--red); }
.pos-item.out { opacity: .55; pointer-events: none; }
.veg, .pos-item .veg { position: relative; width: 15px; height: 15px; border-radius: 3px; background: var(--panel-solid); border: 1.5px solid var(--green); display: grid; place-items: center; flex: none; }
.pos-item .veg { width: clamp(11px, calc(15 * var(--pos-grid-size, 158px) / 158), 20px); height: clamp(11px, calc(15 * var(--pos-grid-size, 158px) / 158), 20px); }
.veg::after, .pos-item .veg::after { content: ""; width: 6.5px; height: 6.5px; border-radius: 50%; background: var(--green); }
.pos-item .veg::after { width: clamp(4.5px, calc(6.5 * var(--pos-grid-size, 158px) / 158), 9px); height: clamp(4.5px, calc(6.5 * var(--pos-grid-size, 158px) / 158), 9px); }
.veg.nonveg, .pos-item .veg.nonveg { border-color: var(--red); } .veg.nonveg::after, .pos-item .veg.nonveg::after { background: var(--red); }

.pos-cart { display: flex; flex-direction: column; border-radius: var(--r-lg); background: var(--panel); border: 1px solid var(--stroke); overflow: hidden; position: sticky; top: 90px; height: calc(100vh - 110px); }
.cart-head { padding: 8px 12px; border-bottom: 1px solid var(--stroke); display: flex; align-items: center; justify-content: space-between; }
.cart-head h3 { font-size: 13px; }
.cart-table-sel { display: flex; gap: 6px; padding: 6px 12px; border-bottom: 1px solid var(--stroke); }
.cart-table-sel select { flex: 1; padding: 4px 6px; font-size: 11.5px; height: 30px; }
.cust-row { display: flex; gap: 6px; padding: 6px 12px 0; }
.cust-row .form-input { padding: 4px 8px; font-size: 11px; border-radius: var(--r-sm); }
.cart-items { flex: 1; overflow-y: auto; padding: 6px 12px; display: flex; flex-direction: column; gap: 5px; min-height: 80px; }
.cart-empty { flex: 1; display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 6px; color: var(--text-faint); text-align: center; padding: 12px; }
.cart-empty i { font-size: 24px; opacity: .5; }
.cart-line { display: flex; gap: 6px; align-items: center; padding: 4px 6px; border-radius: var(--r-sm); background: var(--glass); border: 1px solid var(--stroke); }
.cart-line .cdot { width: 6px; height: 6px; border-radius: 2px; background: var(--cc, var(--orange)); flex: none; }
.cart-line .cinfo { flex: 1; min-width: 0; }
.cart-line .cn { font-size: 12px; font-weight: 600; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.cart-line .cp { font-size: 10px; color: var(--text-mute); }
.qty { display: flex; align-items: center; gap: 4px; }
.qty button { width: 20px; height: 20px; border-radius: 4px; border: 1px solid var(--stroke-2); background: var(--glass-2); color: var(--text); cursor: pointer; font-size: 10px; display: grid; place-items: center; transition: var(--t); }
.qty button:hover { background: var(--orange-tint); color: var(--orange); border-color: rgba(255,79,0,0.4); }
.qty .qn { font-weight: 700; font-size: 11px; min-width: 12px; text-align: center; }
.cart-foot { border-top: 1px solid var(--stroke); padding: 8px 12px; }
.disc-row { display: flex; gap: 6px; margin-bottom: 6px; }
.disc-row .form-input { padding: 4px 8px; font-size: 11px; border-radius: var(--r-sm); }
.totals { display: flex; flex-direction: column; gap: 3px; margin-bottom: 6px; }
.totals .tr { display: flex; justify-content: space-between; font-size: 11px; color: var(--text-soft); }
.totals .tr b { color: var(--text); }
.totals .grand { padding-top: 4px; border-top: 1px dashed var(--stroke-2); }
.totals .grand .lbl { font-weight: 700; font-size: 13px; color: var(--text); }
.totals .grand .amt { font-family: var(--font-display); font-weight: 800; font-size: 18px; color: var(--orange); }
.cart-payment { margin-bottom: 6px; padding: 6px 8px; border: 1px solid var(--stroke); border-radius: var(--r-sm); background: var(--glass); }
.cpay-head { font-size: 11px; font-weight: 700; color: var(--text-soft); margin-bottom: 4px; display: flex; justify-content: space-between; }
.cpay-methods { display: grid; grid-template-columns: repeat(5, 1fr); gap: 4px; margin-bottom: 0; }
.cpay-methods button, .cpay-quick button { border: 1px solid var(--stroke-2); background: var(--panel); color: var(--text-soft); border-radius: 4px; cursor: pointer; font-size: 11px; font-weight: 700; transition: var(--t); }
.cpay-methods button { min-height: 26px; padding: 2px 4px; }
.cpay-methods button:hover { border-color: rgba(255,79,0,0.35); color: var(--orange); background: var(--orange-tint); }
.cpay-methods button.active { border-color: rgba(255,79,0,0.45); background: var(--orange-tint); color: var(--orange); }
.cart-actions { display: grid; grid-template-columns: 1fr 1fr; gap: 6px; }
.cart-actions .btn { padding: 8px; font-size: 11px; }

@media (max-width: 1024px){
  .pos-wrap { grid-template-columns: 1fr; }
  /* Keep the cart panel (and the Print & Pay button) visible on narrow screens
     by stacking it under the menu instead of hiding it behind the mobile cart bar. */
  .pos-cart { display: flex; position: static; max-height: none; margin-bottom: 20px; }
  .pos-cart.active { display: flex !important; position: static; max-height: none; margin-bottom: 20px; }
  .pos-left.hidden { display: none !important; }
  .pos-m-cart-btn { display: flex; }
  .mobile-only-inline { display: inline-flex !important; }

  .pos-toolbar { flex-wrap: wrap; gap: 8px; }
  .pos-search { width: 100%; flex: none; }
  .pos-size-control { flex: 1; justify-content: center; width: 100%; }
  .order-types { width: 100%; justify-content: space-between; gap: 6px; }
  .order-type-btn { flex: 1; justify-content: center; padding: 10px 8px; font-size: 12px; }
  .pos-cat-btn { flex-shrink: 0; }
}

/* ===================== generic list/table ===================== */
.toolbar-row { display: flex; align-items: center; gap: 12px; margin-bottom: 16px; flex-wrap: wrap; }
.toolbar-row .grow { flex: 1; }
.seg { display: inline-flex; gap: 3px; padding: 4px; border-radius: var(--r-pill); background: var(--glass); border: 1px solid var(--stroke-2); }
.seg button { padding: 7px 14px; border-radius: var(--r-pill); border: none; background: none; color: var(--text-soft); font-size: 12.5px; font-weight: 600; cursor: pointer; transition: var(--t); }
.seg button.active { background: var(--orange-tint); color: var(--orange); }

.data-table { width: 100%; border-collapse: collapse; font-size: 13px; }
.data-table thead th { text-align: left; padding: 12px 14px; font-size: 11px; text-transform: uppercase; letter-spacing: 0.06em; color: var(--text-mute); font-weight: 700; border-bottom: 1px solid var(--stroke); white-space: nowrap; }
.data-table tbody td { padding: 13px 14px; border-bottom: 1px solid var(--stroke); color: var(--text-soft); vertical-align: middle; }
.data-table tbody tr { transition: background .2s; }
.data-table tbody tr:hover { background: var(--glass); }
.data-table tbody td b, .data-table .td-strong { color: var(--text); font-weight: 600; }
.row-actions { display: flex; gap: 6px; }
.icon-act { width: 30px; height: 30px; border-radius: 8px; border: 1px solid var(--stroke-2); background: var(--glass); color: var(--text-soft); cursor: pointer; font-size: 12px; display: grid; place-items: center; transition: var(--t); }
.icon-act:hover { color: var(--text); border-color: var(--stroke-hi); transform: translateY(-1px); }
.icon-act.danger:hover { color: var(--red); border-color: oklch(0.66 0.20 25 / 0.4); }
.icon-act.go:hover { color: var(--orange); border-color: rgba(255,79,0,0.4); }
.avatar-sm { width: 30px; height: 30px; border-radius: 9px; display: inline-grid; place-items: center; color: #fff; font-weight: 700; font-size: 12px; font-family: var(--font-display); flex: none; }

.banner { display: flex; align-items: center; gap: 13px; padding: 14px 18px; border-radius: var(--r-md); margin-bottom: 16px; font-size: 13.5px; }
.banner i { font-size: 18px; }
.banner.warn { background: var(--amber-tint); border: 1px solid oklch(0.80 0.15 78 / 0.35); color: var(--amber); }
.banner.warn b { color: var(--text); }
.banner .banner-cta { margin-left: auto; }

/* ===================== QR ORDERS ===================== */
.qr-grid { display: grid; grid-template-columns: repeat(auto-fill,minmax(290px,1fr)); gap: 14px; }
.qr-card { border-radius: var(--r-md); background: var(--panel); border: 1px solid var(--stroke); overflow: hidden; transition: var(--t); }
.qr-card:hover { border-color: var(--stroke-hi); box-shadow: var(--shadow-md); }
.qr-card.s-pending { border-left: 3px solid var(--amber); }
.qr-card.s-preparing { border-left: 3px solid var(--orange); }
.qr-card.s-served { border-left: 3px solid var(--green); }
.qr-ch { display: flex; align-items: center; justify-content: space-between; padding: 13px 15px; border-bottom: 1px solid var(--stroke); }
.qr-ch .tnum { font-family: var(--font-display); font-weight: 800; font-size: 15px; }
.qr-ch .qtime { font-size: 11.5px; color: var(--text-mute); }
.qr-lines { padding: 12px 15px; display: flex; flex-direction: column; gap: 7px; }
.qr-lines .ql { display: flex; justify-content: space-between; font-size: 13px; color: var(--text-soft); }
.qr-lines .ql b { color: var(--text); }
.qr-cf { padding: 11px 15px; border-top: 1px solid var(--stroke); display: flex; gap: 8px; align-items: center; }
.qr-cf .qtot { font-family: var(--font-display); font-weight: 800; color: var(--orange); margin-right: auto; }

/* ===================== KDS ===================== */
.kds-grid { display: grid; grid-template-columns: repeat(auto-fill,minmax(280px,1fr)); gap: 14px; }
.kds-card { border-radius: var(--r-md); background: var(--panel); border: 1px solid var(--stroke); overflow: hidden; display: flex; flex-direction: column; }
.kds-card.urgent { border-color: oklch(0.66 0.20 25 / 0.5); box-shadow: 0 0 0 1px oklch(0.66 0.20 25 / 0.3), var(--shadow-md); animation: urgentpulse 2s infinite; }
@keyframes urgentpulse { 0%,100%{box-shadow:0 0 0 1px oklch(0.66 0.20 25 / 0.3), var(--shadow-md);} 50%{box-shadow:0 0 0 3px oklch(0.66 0.20 25 / 0.18), var(--shadow-md);} }
.kds-h { display: flex; align-items: center; justify-content: space-between; gap: 10px; padding: 13px 15px; border-bottom: 1px solid var(--stroke); background: var(--glass); }
.kds-h .ktok { font-family: var(--font-display); font-weight: 800; font-size: 17px; white-space: nowrap; }
.kds-h .ktype { font-size: 11px; color: var(--text-mute); }
.kds-timer { font-family: var(--font-display); font-weight: 800; font-size: 15px; padding: 4px 11px; border-radius: 99px; background: var(--green-tint); color: var(--green); font-variant-numeric: tabular-nums; white-space: nowrap; flex: none; }
.kds-timer.mid { background: var(--amber-tint); color: var(--amber); }
.kds-timer.late { background: var(--red-tint); color: var(--red); }
.kds-items { padding: 12px 15px; flex: 1; display: flex; flex-direction: column; gap: 9px; }
.kds-item { display: flex; gap: 10px; align-items: flex-start; font-size: 13.5px; }
.kds-item .kq { font-family: var(--font-display); font-weight: 800; color: var(--orange); flex: none; min-width: 24px; }
.kds-item .knote { font-size: 11.5px; color: var(--amber); }
.kds-item.done .kn { text-decoration: line-through; color: var(--text-faint); }
.kds-foot { padding: 12px 15px; border-top: 1px solid var(--stroke); }

/* ===================== REPORTS / charts ===================== */
.report-grid { display: grid; grid-template-columns: var(--cols, 1.6fr 1fr); gap: 16px; }
.chart-bars { display: flex; align-items: flex-end; gap: 10px; height: 200px; padding-top: 10px; }
.chart-bars .cbar { flex: 1; display: flex; flex-direction: column; align-items: center; gap: 8px; height: 100%; justify-content: flex-end; }
.chart-bars .cbar .bar { width: 100%; max-width: 38px; border-radius: 8px 8px 4px 4px; background: linear-gradient(180deg, var(--orange-soft), var(--orange-deep)); transition: height 1s var(--ease); position: relative; }
.chart-bars .cbar .bar.v { background: linear-gradient(180deg, var(--violet-soft), var(--violet)); }
.chart-bars .cbar .bl { font-size: 11px; color: var(--text-mute); }
.chart-bars .cbar .bv { position: absolute; top: -20px; left: 50%; transform: translateX(-50%); font-size: 11px; font-weight: 700; color: var(--text); white-space: nowrap; opacity: 0; transition: opacity .2s; }
