.product-guide-backdrop {
  position: absolute;
  inset: 0;
  background: rgba(8, 8, 11, 0.72);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
}

.product-guide-panel {
  position: absolute;
  inset: 24px;
  width: min(1080px, calc(100vw - 48px));
  margin: auto;
  padding: 28px 24px;
  overflow-y: auto;
  border: 1px solid var(--stroke-2);
  border-radius: var(--r-md, 16px);
  background: var(--panel-solid);
  box-shadow: var(--shadow-lg);
  font-family: var(--font-body), sans-serif;
  color: var(--text);
}

.product-guide-header,
.product-guide-toolbar,
.product-guide-section-heading,
.product-guide-progress-copy {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
}

.product-guide-header h2 {
  margin: 4px 0;
  color: var(--text);
  font-family: var(--font-display), sans-serif;
  font-size: 24px;
  font-weight: 800;
}

.product-guide-header p {
  margin: 0;
  color: var(--text-soft);
  font-size: 12px;
}

.product-guide-eyebrow,
.product-guide-section-heading span,
.product-guide-progress-copy span {
  color: var(--orange);
  font-size: 9px;
  font-weight: 800;
  letter-spacing: 0.12em;
}

.product-guide-close {
  width: 38px;
  height: 38px;
  flex: 0 0 auto;
  border: 1px solid var(--stroke-2);
  border-radius: var(--r-xs, 8px);
  background: var(--glass);
  color: var(--text);
  font-size: 22px;
  cursor: pointer;
  transition: all 0.2s;
}

.product-guide-close:hover {
  background: var(--glass-3);
  border-color: var(--stroke-hi);
}

.product-guide-toolbar {
  margin: 20px 0;
}

.product-guide-toolbar input {
  width: min(360px, 100%);
  min-height: 40px;
  padding: 9px 12px;
  border: 1px solid var(--stroke-2);
  border-radius: var(--r-xs, 8px);
  background: var(--glass);
  color: var(--text);
  font-family: var(--font-body), sans-serif;
  transition: all 0.2s;
}

.product-guide-toolbar input:focus {
  border-color: var(--orange);
  outline: none;
  background: var(--glass-2);
}

.product-guide-setup {
  padding: 18px;
  border: 1px solid rgba(255, 79, 0, 0.16);
  border-radius: var(--r-sm, 12px);
  background: rgba(255, 79, 0, 0.04);
}

.product-guide-progress-copy strong {
  display: block;
  margin-top: 3px;
  color: var(--text);
  font-size: 13px;
}

.product-guide-progress-copy b {
  color: var(--orange);
  font-size: 20px;
}

.product-guide-progress {
  height: 7px;
  margin: 12px 0 16px;
  overflow: hidden;
  border-radius: var(--r-pill, 999px);
  background: var(--stroke);
}

.product-guide-progress span {
  display: block;
  height: 100%;
  border-radius: inherit;
  background: var(--orange);
}

.product-guide-task-grid,
.product-guide-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

.product-guide-task {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr) auto;
  align-items: center;
  gap: 10px;
  padding: 12px;
  border: 1px solid var(--stroke);
  border-radius: var(--r-xs, 8px);
  background: var(--glass);
  color: var(--text);
  text-align: left;
  cursor: pointer;
  transition: all 0.2s;
}

.product-guide-task:hover {
  border-color: var(--stroke-hi);
  background: var(--glass-2);
}

.product-guide-task > i:first-child {
  color: var(--text-faint);
}

.product-guide-task.is-done > i:first-child {
  color: var(--green);
}

.product-guide-task span {
  min-width: 0;
}

.product-guide-task strong,
.product-guide-task small {
  display: block;
}

.product-guide-task strong {
  font-size: 12px;
  font-weight: 700;
}

.product-guide-task small {
  margin-top: 2px;
  color: var(--text-soft);
  font-size: 10px;
  line-height: 1.35;
}

.product-guide-section-heading {
  margin: 24px 0 12px;
}

.product-guide-section-heading h3 {
  margin: 3px 0 0;
  color: var(--text);
  font-family: var(--font-display), sans-serif;
  font-size: 17px;
  font-weight: 700;
}

.product-guide-count {
  padding: 5px 8px;
  border-radius: var(--r-pill, 999px);
  background: var(--orange-tint);
  color: var(--orange);
  font-size: 11px;
  font-weight: 700;
}

.product-guide-card {
  display: flex;
  gap: 14px;
  padding: 16px;
  border: 1px solid var(--stroke);
  border-radius: var(--r-sm, 12px);
  background: var(--glass);
  transition: all 0.2s;
}

.product-guide-card:hover {
  border-color: var(--stroke-hi);
  background: var(--glass-2);
}

.product-guide-card-icon {
  display: grid;
  width: 40px;
  height: 40px;
  flex: 0 0 40px;
  place-items: center;
  border-radius: var(--r-xs, 8px);
  background: var(--orange-tint);
  color: var(--orange);
  font-size: 16px;
}

.product-guide-card-copy {
  flex: 1;
}

.product-guide-card-copy > span {
  color: var(--orange);
  font-size: 9px;
  font-weight: 800;
  text-transform: uppercase;
}

.product-guide-card h4 {
  margin: 3px 0 7px;
  color: var(--text);
  font-family: var(--font-display), sans-serif;
  font-size: 14px;
  font-weight: 700;
}

.product-guide-card p,
.product-guide-first-action {
  color: var(--text-soft);
  font-size: 11px;
  line-height: 1.5;
}

.product-guide-first-action {
  margin-top: 9px;
  padding: 8px 10px;
  border-radius: var(--r-xs, 8px);
  background: var(--glass-2);
  border-left: 3px solid var(--orange);
}

.product-guide-card button {
  margin-top: 11px;
  padding: 0;
  border: 0;
  background: transparent;
  color: var(--orange);
  font-family: var(--font-display), sans-serif;
  font-size: 11px;
  font-weight: 800;
  cursor: pointer;
}

.product-guide-empty {
  grid-column: 1 / -1;
  padding: 28px;
  color: var(--text-soft);
  text-align: center;
}

body.product-guide-open {
  overflow: hidden;
}

@media (max-width: 720px) {
  .product-guide-panel {
    inset: 0;
    width: 100%;
    padding: 18px 16px calc(90px + env(safe-area-inset-bottom));
    border: 0;
    border-radius: 0;
  }

  .product-guide-header,
  .product-guide-toolbar {
    align-items: stretch;
  }

  .product-guide-toolbar,
  .product-guide-header {
    flex-direction: column;
  }

  .product-guide-close {
    position: absolute;
    top: 14px;
    right: 14px;
  }

  .product-guide-toolbar input,
  .product-guide-toolbar .btn {
    width: 100%;
  }

  .product-guide-task-grid,
  .product-guide-grid {
    grid-template-columns: 1fr;
  }
}

/* ================================================================
   RESTROSUITE — MOBILE & TABLET RESPONSIVE FIXES
   Fixes: 1(sidebar) 2(POS grid) 3(touch) 4(iOS zoom) 6(header) 7(tablet)
   ================================================================ */

/* Fix 1 — Hamburger button & overlay */
.sidebar-hamburger {
  display: none;
  position: fixed;
  top: 14px;
  left: 14px;
  z-index: 200;
  width: 44px;
  height: 44px;
  border-radius: 10px;
  background: var(--white, #fff);
  border: 1px solid var(--stroke-2, #E5E7EB);
  box-shadow: 0 2px 8px rgba(0,0,0,.10);
  align-items: center;
  justify-content: center;
  cursor: pointer;
  font-size: 18px;
  color: var(--text, #111827);
  transition: background-color .15s ease, box-shadow .15s ease;
}
.sidebar-hamburger:hover,
.sidebar-hamburger:focus-visible {
  background: var(--glass-2, #F6F7F9);
  box-shadow: 0 4px 14px rgba(0,0,0,.14);
  outline: 2px solid var(--orange, #FF6B00);
}
.sidebar-overlay {
  display: none;
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,.45);
  z-index: 140;
  backdrop-filter: blur(2px);
  -webkit-backdrop-filter: blur(2px);
}

@media (min-width: 761px) and (max-width: 1024px) {
  .sidebar-hamburger { display: flex; }
  .sidebar-overlay.active { display: block; }
  
  /* Sidebar drawer behavior for mobile/tablet */
  .sidebar {
    position: fixed !important;
    top: 0;
    left: 0;
    height: 100vh;
    z-index: 150;
    transform: translateX(-100%);
    transition: transform 0.3s var(--ease);
    display: flex !important; /* overrides display: none at max-width: 760px */
    width: 264px !important;
    box-shadow: 10px 0 30px rgba(0,0,0,0.25);
  }
  .sidebar.reveal {
    transform: translateX(0) !important;
  }
  
  /* Fix 7 — Tablet breakpoint: ensure full-width content area */
  .main-content, .main {
    margin-left: 0 !important;
    width: 100% !important;
  }
}

/* Fix 2 — POS layout: tablet gets narrower cart, phone gets stacked */
@media (max-width: 1024px) and (min-width: 641px) {
  .pos-wrap {
    grid-template-columns: 1fr 300px !important;
  }
}
@media (max-width: 640px) {
  .pos-wrap {
    grid-template-columns: 1fr !important;
  }
}

/* Fix 3 — Touch targets >= 44px on tablet/mobile */
@media (max-width: 1024px) {
  .pos-cat-btn {
    height: 44px !important;
    padding: 0 20px !important;
  }
  .pos-search input {
    height: 44px !important;
    padding: 0 14px 0 38px !important;
  }
  .pos-customize-btn {
    width: 44px !important;
    height: 44px !important;
    min-height: 44px !important;
    opacity: 1 !important;
  }
  .cust-qty-btn {
    width: 40px !important;
    height: 40px !important;
  }
  .cart-qty-btn {
    min-width: 36px !important;
    min-height: 36px !important;
  }
  .sidebar-link {
    min-height: 44px !important;
    padding-top: 10px !important;
    padding-bottom: 10px !important;
  }
}

/* Fix 4 — Input font-size >= 16px (prevents iOS auto-zoom on focus) */
@media (max-width: 768px) {
  input,
  select,
  textarea {
    font-size: 16px !important;
  }
}

/* Fix 6 — Reduce dashboard header padding on small screens */
@media (max-width: 768px) {
  .dashboard-header {
    padding: 10px 14px !important;
    gap: 6px;
  }
  .header-meta,
  .header-date,
  .header-secondary {
    display: none !important;
  }
}

/* Fix 7 — Phone: stack multi-column views */
@media (max-width: 768px) {
  .staff-access-view.active {
    grid-template-columns: 1fr !important;
  }
  .kds-grid,
  .orders-grid {
    grid-template-columns: 1fr !important;
  }
  .view-panel,
  .tab-panel,
  .section-inner {
    padding: 12px !important;

}

/* Tab blinking/pulse attention effect */
@keyframes tab-attention-pulse {
  0% {
    background-color: transparent;
  }
  50% {
    background-color: rgba(255, 79, 0, 0.15);
  }
  100% {
    background-color: transparent;
  }
}

.sidebar-link.attention-blink {
  animation: tab-attention-pulse 1.5s infinite ease-in-out;
  color: var(--orange) !important;
  box-shadow: inset 3px 0 0 var(--orange) !important;
}

.mnav-link.attention-blink {
  animation: tab-attention-pulse 1.5s infinite ease-in-out;
  color: var(--orange) !important;
  box-shadow: inset 0 -3px 0 var(--orange) !important;
}

.sidebar-link.attention-blink i, .mnav-link.attention-blink i {
  color: var(--orange) !important;
}


