  .step-dot { width: 30px; height: 30px; border-radius: 50%; display: grid; place-items: center; font-size: 13px; font-weight: 700; font-family: var(--font-display); background: var(--glass-2); border: 1px solid var(--stroke-2); color: var(--text-mute); transition: var(--t); }
  .step-node.active .step-dot { background: linear-gradient(135deg,var(--orange-soft),var(--orange-deep)); color: #fff; border-color: transparent; box-shadow: var(--glow-orange); }
  .step-node.done .step-dot { background: var(--green-tint); border-color: oklch(0.74 0.15 158 / 0.4); color: var(--green); }
  .step-node .step-label { font-size: 12.5px; font-weight: 600; color: var(--text-mute); }
  .step-node.active .step-label, .step-node.done .step-label { color: var(--text); }
  .step-line { flex: 1; height: 2px; background: var(--stroke-2); margin: 0 12px; border-radius: 2px; overflow: hidden; }
  .step-line span { display: block; height: 100%; width: 0; background: var(--orange); transition: width .5s var(--ease); }

  .reg-step { display: none; }
  .reg-step.on { display: block; animation: fadein .4s var(--ease); }
  @keyframes fadein { from { opacity: 0; transform: translateX(12px);} to { opacity: 1; transform: none;} }
  .step-actions { display: flex; gap: 12px; margin-top: 8px; }

  /* plan picker */
  .plan-pick { display: grid; gap: 10px; margin-bottom: 4px; }
  .plan-opt { display: flex; align-items: center; gap: 13px; padding: 14px; border-radius: var(--r-sm); border: 1px solid var(--stroke-2); background: var(--glass); cursor: pointer; transition: var(--t); }
  .plan-opt:hover { border-color: var(--stroke-hi); }
  .plan-opt.sel { border-color: var(--orange); background: var(--orange-tint); }
  .plan-radio { width: 18px; height: 18px; border-radius: 50%; border: 2px solid var(--stroke-hi); flex: none; display: grid; place-items: center; transition: var(--t); }
  .plan-opt.sel .plan-radio { border-color: var(--orange); }
  .plan-opt.sel .plan-radio::after { content: ""; width: 9px; height: 9px; border-radius: 50%; background: var(--orange); }
  .plan-opt .pn { font-weight: 700; font-size: 14.5px; }
  .plan-opt .pd { font-size: 12px; color: var(--text-mute); }
  .plan-opt .pp { margin-left: auto; font-family: var(--font-display); font-weight: 800; font-size: 16px; color: var(--orange); }

  /* recovery modal */
  .recovery-modal { position: fixed; inset: 0; z-index: 1000; display: none; align-items: center; justify-content: center; padding: 20px; background: rgba(4,4,8,0.6); -webkit-backdrop-filter: blur(8px); backdrop-filter: blur(8px); }
  .recovery-modal.active { display: flex; }
  .recovery-card { width: 100%; max-width: 460px; border-radius: var(--r-lg); padding: 30px; background: var(--panel-solid); border: 1px solid var(--stroke-2); box-shadow: var(--shadow-lg); animation: pop .4s var(--ease-spring); }
  @keyframes pop { from { opacity: 0; transform: scale(.94) translateY(10px);} to { opacity: 1; transform: none;} }
  .recovery-head { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 22px; }
  .recovery-head h3 { font-size: 20px; margin-bottom: 5px; }
  .recovery-head p { font-size: 13px; color: var(--text-soft); max-width: 320px; }
  .recovery-close { background: var(--glass-2); border: 1px solid var(--stroke-2); width: 34px; height: 34px; border-radius: 50%; font-size: 16px; cursor: pointer; color: var(--text-soft); flex: none; transition: var(--t); }
  .recovery-close:hover { color: var(--text); border-color: var(--stroke-hi); }
  .recovery-tabs { display: flex; gap: 8px; margin-bottom: 18px; }
  .rtab { flex: 1; padding: 9px; border-radius: var(--r-sm); border: 1px solid var(--stroke-2); background: var(--glass); color: var(--text-soft); font-size: 12.5px; font-weight: 600; cursor: pointer; transition: var(--t); }
  .rtab.active { background: var(--orange-tint); color: var(--orange); border-color: rgba(255,79,0,0.4); }
  .rform { display: none; } .rform.on { display: block; }
  .otp-row { display: flex; gap: 10px; justify-content: space-between; margin-bottom: 8px; }
  .otp-row input { width: 100%; text-align: center; font-family: var(--font-display); font-weight: 800; font-size: 20px; padding: 12px 0; border: 1px solid var(--stroke-2); border-radius: var(--r-sm); background: var(--glass); color: var(--text); }
  .otp-row input:focus { outline: none; border-color: var(--orange); box-shadow: 0 0 0 4px rgba(255,79,0,0.12); }
  .resend { text-align: center; font-size: 12.5px; color: var(--text-mute); margin-bottom: 8px; }

  .access-foot { text-align: center; padding: 20px; color: var(--text-mute); font-size: 13px; border-top: 1px solid var(--stroke); }

  .shake { animation: shake .45s var(--ease); }
  @keyframes shake { 10%,90%{transform:translateX(-1px);} 30%,70%{transform:translateX(-5px);} 50%{transform:translateX(5px);} }

  @media (max-width: 920px) { .access-main { grid-template-columns: 1fr; } .access-story { min-height: auto; order: 2; } .login-container { order: 1; } }
  @media (max-width: 540px) { .login-card { padding: 26px 22px; } .form-grid { grid-template-columns: 1fr; } }
</style>
</head>
<body class="noise">

