</div>

<main class="access-main">
  <!-- LEFT -->
  <section class="access-story" data-screen-label="marketing">
    <div class="story-inner">
      <a class="brand brand-lockup" href="index.html">
        <img class="brand-logo" src="assets/restrosuite-mark.png" alt="RestroSuite">
        <span class="brand-name">
          <span class="codearc">CodeArc</span>
          Restro<b>Suite</b>
        </span>
      </a>

      <div class="story-slides" id="story-slides">
        <div class="story-slide on">
          <div class="story-stat"><span class="big" data-count="4.5">0</span><span class="suf">hours / day</span></div>
          <h2>Save 4.5 hours daily.</h2>
          <p>Automated billing, KOT routing and reconciliation hand your team back hours every single shift.</p>
        </div>
        <div class="story-slide">
          <div class="story-stat"><span class="big" data-count="100">0</span><span class="suf">% cloud sync</span></div>
          <h2>Never lose a sale.</h2>
          <p>Keep ringing up orders through power cuts and dead zones — everything syncs to the cloud the moment you reconnect.</p>
        </div>
        <div class="story-slide">
          <div class="story-stat"><span class="big" data-count="0" data-prefix="₹">0</span><span class="suf">setup cost</span></div>
          <h2>Zero hardware to buy.</h2>
          <p>Runs on the phone, tablet or laptop you already own. Live in minutes, not weeks.</p>
        </div>
      </div>

      <div class="story-dots" id="story-dots"></div>

      <div class="story-feats">
        <div class="story-feat"><i class="fa-solid fa-shield-halved"></i> Role-controlled access for every staff member</div>
        <div class="story-feat"><i class="fa-brands fa-whatsapp"></i> GST receipts delivered to WhatsApp instantly</div>
        <div class="story-feat"><i class="fa-solid fa-lock"></i> Bank-grade encryption · your data stays yours</div>
      </div>
    </div>
  </section>

  <!-- RIGHT -->
  <div class="login-container">
    <div class="login-card" id="login-card" data-screen-label="auth-card">
      <div class="auth-head">
        <div class="brand brand-lockup">
          <img class="brand-logo" src="assets/restrosuite-mark.png" alt="RestroSuite">
          <span class="brand-name">
            <span class="codearc">CodeArc</span>
            Restro<b>Suite</b>
          </span>
        </div>
        <h2 class="login-title" id="portal-title">Sign in to your workspace</h2>
        <p class="login-subtitle" id="portal-subtitle">Enter your outlet ID and the credentials assigned to you.</p>
      </div>

      <div class="tab-header" role="tablist">
        <button class="tab-btn active" id="tab-login-btn" type="button" role="tab" aria-selected="true">Sign in</button>
        <button class="tab-btn" id="tab-register-btn" type="button" role="tab" aria-selected="false">Register outlet</button>
      </div>

      <div class="alert err" id="error-box" role="alert"><i class="fa-solid fa-circle-exclamation"></i><span></span></div>
      <div class="alert ok" id="success-box" role="status"><i class="fa-solid fa-circle-check"></i><span></span></div>

      <!-- LOGIN -->
      <form id="login-form" role="tabpanel">
        <div class="form-group">
          <label for="tenant-id">Workspace / Outlet ID</label>
          <div class="input-wrap"><i class="fa-solid fa-hotel lead"></i>
            <input type="text" id="tenant-id" class="form-input" placeholder="e.g. royal-dhaba" autocomplete="organization" autocapitalize="none" spellcheck="false" required>
          </div>
          <p class="field-help">Use the outlet ID from registration, not the display name.</p>
        </div>
        <div class="form-group">
          <label for="username">Email or Username</label>
          <div class="input-wrap"><i class="fa-solid fa-user lead"></i>
            <input type="text" id="username" class="form-input" placeholder="you@outlet.com" autocomplete="username" required>
          </div>
        </div>
        <div class="form-group">
          <label for="password">Password</label>
          <div class="input-wrap"><i class="fa-solid fa-lock lead"></i>
            <input type="password" id="password" class="form-input" placeholder="••••••••" autocomplete="current-password" required>
            <button class="toggle-pwd" id="toggle-pwd" type="button" aria-label="Show password"><i class="fa-solid fa-eye"></i></button>
          </div>
        </div>
        <div class="row-between">
          <label class="remember"><input type="checkbox" id="remember-me" checked> Keep me signed in</label>
          <button type="button" class="link-btn" id="open-recovery-btn">Forgot password?</button>
        </div>
        <button type="submit" class="btn btn-primary btn-block btn-lg" id="login-submit">Sign in securely <i class="fa-solid fa-right-to-bracket"></i></button>
        <div class="note"><i class="fa-solid fa-shield-halved"></i><span>Your outlet, role and subscription status are verified before dashboard access is granted.</span></div>
      </form>

      <!-- REGISTER (multi-step) -->
      <form id="register-form" style="display:none">
        <div class="steps-bar">
          <div class="step-node active" id="snode-1"><span class="step-dot">1</span><span class="step-label">Outlet</span></div>
          <div class="step-line"><span id="step-progress"></span></div>
          <div class="step-node" id="snode-2"><span class="step-dot">2</span><span class="step-label">Owner</span></div>
        </div>

        <!-- step 1 -->
        <div class="reg-step on" id="reg-step-1">
          <div class="form-group full">
            <label for="reg-name">Restaurant / Business name</label>
            <div class="input-wrap"><i class="fa-solid fa-store lead"></i>
              <input type="text" id="reg-name" class="form-input" placeholder="e.g. Royal Restaurant &amp; Dhaba" autocomplete="organization" required>
            </div>
          </div>
          <div class="form-grid">
            <div class="form-group">
              <label for="reg-slug">Workspace code</label>
              <div class="input-wrap"><i class="fa-solid fa-link lead"></i>
                <input type="text" id="reg-slug" class="form-input" placeholder="royal-dhaba" autocapitalize="none" spellcheck="false" required>
              </div>
              <div class="field-status" id="slug-status"></div>
            </div>
            <div class="form-group">
              <label for="reg-type">Outlet type</label>
              <select id="reg-type" class="form-input no-icon">
                <option value="restaurant">Restaurant</option>
                <option value="cafe">Café / Bakery</option>
                <option value="dhaba">Dhaba / Diner</option>
                <option value="cart">Food Cart / Truck</option>
                <option value="cloud">Cloud Kitchen</option>
              </select>
            </div>
          </div>
          <div class="form-group full">
            <label for="reg-address">Outlet address</label>
            <div class="input-wrap"><i class="fa-solid fa-location-dot lead"></i>
              <input type="text" id="reg-address" class="form-input" placeholder="Shop no., street, city, PIN" autocomplete="street-address" required>
            </div>
          </div>
          <div class="form-group full">
            <label>Choose your plan</label>
            <div class="plan-pick" id="plan-pick">
              <div class="plan-opt" data-plan="free"><span class="plan-radio"></span><div><div class="pn">Free / Demo</div><div class="pd">Full POS simulator &amp; training database</div></div><span class="pp">₹0</span></div>
              <div class="plan-opt" data-plan="starter"><span class="plan-radio"></span><div><div class="pn">Starter</div><div class="pd">Offline POS &amp; billing essentials</div></div><span class="pp">₹499</span></div>
              <div class="plan-opt sel" data-plan="growth"><span class="plan-radio"></span><div><div class="pn">Growth <span class="pill pill-orange" style="padding:2px 8px;font-size:10px">Popular</span></div><div class="pd">Full suite — QR, KDS, CRM, reports</div></div><span class="pp">₹749</span></div>
              <div class="plan-opt" data-plan="chain"><span class="plan-radio"></span><div><div class="pn">Chain</div><div class="pd">Multi-outlet central control</div></div><span class="pp">₹1,999</span></div>
            </div>
            <input type="hidden" id="reg-plan" value="growth">
          </div>
          <div class="step-actions">
            <button type="button" class="btn btn-primary btn-block btn-lg" id="reg-next">Continue to owner details <i class="fa-solid fa-arrow-right"></i></button>
          </div>
        </div>

        <!-- step 2 -->
        <div class="reg-step" id="reg-step-2">
          <div class="form-group full">
            <label for="reg-owner">Owner full name</label>
            <div class="input-wrap"><i class="fa-solid fa-user-tie lead"></i>
              <input type="text" id="reg-owner" class="form-input" placeholder="e.g. Ravi Kumar" autocomplete="name" required>
            </div>
          </div>
          <div class="form-group full">
            <label for="reg-email">Owner email</label>
            <div class="input-wrap"><i class="fa-solid fa-envelope lead"></i>
              <input type="email" id="reg-email" class="form-input" placeholder="owner@email.com" autocomplete="email" required>
            </div>
          </div>
          <div class="form-group full">
            <label for="reg-password">Create password</label>
            <div class="input-wrap"><i class="fa-solid fa-lock lead"></i>
              <input type="password" id="reg-password" class="form-input" placeholder="At least 10 characters" autocomplete="new-password" minlength="10" required>
              <button class="toggle-pwd" type="button" data-toggle="reg-password" aria-label="Show password"><i class="fa-solid fa-eye"></i></button>
            </div>
          </div>
          <div class="form-group full">
            <label for="reg-whatsapp">WhatsApp mobile number</label>
            <div class="phone-wrap">
              <select id="reg-country-code" class="phone-prefix">
                <option value="91" selected>🇮🇳 +91</option>
              </select>
              <input type="tel" id="reg-whatsapp" class="form-input" placeholder="98765 43210" autocomplete="tel" required>
              <i class="fa-brands fa-whatsapp wa"></i>
            </div>
            <p class="field-help">Receipts &amp; account alerts are sent here. We never share it.</p>
