      </div>
      <div class="form-group">
        <label for="recovery-confirm-password">Confirm new password</label>
        <div class="input-wrap"><i class="fa-solid fa-shield-halved lead"></i>
          <input type="password" id="recovery-confirm-password" class="form-input" minlength="10" placeholder="Repeat new password" autocomplete="new-password" required>
        </div>
      </div>
      <button type="submit" class="btn btn-primary btn-block btn-lg">Set new password <i class="fa-solid fa-circle-check"></i></button>
    </form>
  </section>
</div>

