        <div class="reg-step" id="reg-step-2">
          <div class="form-group full">
            <label for="reg-owner">Owner full name</label>
            <div class="input-wrap"><i class="fa-solid fa-user-tie lead"></i>
              <input type="text" id="reg-owner" class="form-input" placeholder="e.g. Ravi Kumar" autocomplete="name" required>
