      font-size: 14.5px; font-weight: 600; color: var(--text-dim);
      padding: 9px 14px; border-radius: 10px; transition: color .2s, background .2s;
    }
    .nav-links a:hover { color: var(--text); background: var(--hover); }
    .nav-cta-group { display: flex; align-items: center; gap: 10px; }
    .theme-toggle {
      width: 40px; height: 40px; border-radius: 11px; border: 1px solid var(--border-2);
      background: var(--surface-2); color: var(--text-dim); display: grid; place-items: center;
      font-size: 15px; transition: all .2s;
    }
    .theme-toggle:hover { color: var(--accent); border-color: var(--accent-line); }
    .link-signin { font-size: 14.5px; font-weight: 600; color: var(--text-dim); padding: 10px 14px; border-radius: 10px; }
    .link-signin:hover { color: var(--text); }

    /* Hero */
    .hero { padding: 150px 0 90px; }
    .hero-grid { display: grid; grid-template-columns: 1.05fr .95fr; gap: 56px; align-items: center; }
    .hero-flag {
      display: inline-flex; align-items: center; gap: 9px; margin-bottom: 26px;
      padding: 7px 7px 7px 14px; border-radius: 999px;
      background: var(--surface-2); border: 1px solid var(--border-2); font-size: 13px; color: var(--text-dim);
      animation: fadeUp .6s both;
    }
    .hero-flag b { color: var(--accent); }
    .hero-flag .pill { background: var(--accent-soft); color: var(--accent); font-weight: 700; padding: 3px 10px; border-radius: 999px; font-size: 12px; }
    .hero h1 {
      font-size: clamp(38px, 5.4vw, 66px); line-height: 1.03; letter-spacing: -.035em;
      margin-bottom: 22px; animation: fadeUp .6s .05s both; text-wrap: balance;
    }
    .hero h1 .grad {
      background: linear-gradient(110deg, var(--accent) 10%, #ff8a3d 55%, var(--teal) 130%);
      -webkit-background-clip: text; background-clip: text; -webkit-text-fill-color: transparent;
    }
    .hero-sub { font-size: 18px; color: var(--text-dim); max-width: 540px; margin-bottom: 32px; animation: fadeUp .6s .1s both; }
    .hero-actions { display: flex; flex-wrap: wrap; align-items: center; gap: 14px; animation: fadeUp .6s .15s both; }
    .hero-trust { display: flex; align-items: center; gap: 22px; margin-top: 30px; flex-wrap: wrap; animation: fadeUp .6s .2s both; }
    .hero-trust .t-item { display: flex; align-items: center; gap: 9px; font-size: 13.5px; color: var(--text-dim); }
    .hero-trust .t-item i { color: var(--teal); }

    /* Hero mockup — floating glass POS dashboard */
    .hero-visual { position: relative; animation: fadeUp .7s .2s both; }
    .hero-mockup { padding: 18px; position: relative; z-index: 2; animation: floaty 7s ease-in-out infinite; }
    .mock-top { display: flex; align-items: center; justify-content: space-between; padding: 4px 6px 16px; }
    .mock-dots { display: flex; gap: 6px; }
    .mock-dots span { width: 10px; height: 10px; border-radius: 50%; background: var(--border-strong); }
    .mock-dots span:first-child { background: var(--accent); }
    .mock-label { font-size: 12px; font-weight: 600; color: var(--text-mute); }
    .mock-stat-row { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-bottom: 12px; }
    .mock-stat { padding: 15px; border-radius: 15px; background: var(--surface-2); border: 1px solid var(--border); }
    .mock-stat .k { font-size: 12px; color: var(--text-mute); margin-bottom: 6px; }
    .mock-stat .v { font-family: "Plus Jakarta Sans"; font-size: 24px; font-weight: 800; letter-spacing: -.02em; }
    .mock-stat .v small { font-size: 13px; color: var(--success); font-weight: 700; }
    .mock-chart { padding: 16px; border-radius: 15px; background: var(--surface-2); border: 1px solid var(--border); }
    .mock-chart .ch-head { display: flex; justify-content: space-between; align-items: center; margin-bottom: 14px; }
    .mock-chart .ch-head .t { font-size: 13px; font-weight: 700; }
    .bars { display: flex; align-items: flex-end; gap: 8px; height: 86px; }
    .bars .bar { flex: 1; border-radius: 6px 6px 3px 3px; background: linear-gradient(180deg, var(--accent), color-mix(in srgb, var(--accent) 40%, transparent)); opacity: .85; }
    .bars .bar.teal { background: linear-gradient(180deg, var(--teal), color-mix(in srgb, var(--teal) 35%, transparent)); }
    .float-chip {
      position: absolute; z-index: 3; padding: 12px 15px; border-radius: 15px;
      display: flex; align-items: center; gap: 11px; font-size: 13px; font-weight: 600;
    }
    .float-chip .ic { width: 34px; height: 34px; border-radius: 10px; display: grid; place-items: center; font-size: 15px; }
    .float-chip.wa { top: -22px; right: 8%; animation: floaty 5.5s ease-in-out infinite; }
    .float-chip.wa .ic { background: var(--success-soft); color: var(--success); }
    .float-chip.sync { bottom: 30px; left: -38px; animation: floaty 6.5s ease-in-out .8s infinite; }
    .float-chip.sync .ic { background: var(--teal-soft); color: var(--teal); }
    .float-chip .sm { display: block; font-size: 11px; font-weight: 500; color: var(--text-mute); }

    /* Logo strip */
    .logo-strip { padding: 16px 0 40px; }
    .logo-strip .lbl { text-align: center; font-size: 12px; letter-spacing: .16em; text-transform: uppercase; color: var(--text-mute); margin-bottom: 22px; }
    .logo-row { display: flex; flex-wrap: wrap; justify-content: center; gap: 14px 40px; opacity: .75; }
    .logo-row span { font-family: "Plus Jakarta Sans"; font-weight: 800; font-size: 19px; color: var(--text-dim); letter-spacing: -.02em; }

    /* Section scaffolding */
    .section { padding: 96px 0; position: relative; }
    .section-head { max-width: 660px; margin: 0 auto 58px; text-align: center; display: flex; flex-direction: column; align-items: center; gap: 15px; }
    .section-head h2 { font-size: clamp(30px, 4vw, 46px); line-height: 1.12; letter-spacing: -.03em; text-wrap: balance; }
    .section-head p { font-size: 17px; color: var(--text-dim); margin: 0; }

    /* Features */
    .features-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 20px; }
    .feature-card { padding: 28px 24px; transition: transform .3s, border-color .3s, box-shadow .3s; }
    .feature-card:hover { transform: translateY(-6px); border-color: var(--border-strong); box-shadow: var(--shadow-lg); }
    .feature-ic { width: 52px; height: 52px; border-radius: 14px; display: grid; place-items: center; font-size: 21px; margin-bottom: 20px;
      background: var(--accent-soft); color: var(--accent); border: 1px solid var(--accent-line); }
    .feature-card.t2 .feature-ic { background: var(--teal-soft); color: var(--teal); border-color: transparent; }
    .feature-card h3 { font-size: 19px; margin-bottom: 9px; }
    .feature-card p { font-size: 14.5px; color: var(--text-dim); }
    .feature-card .learn { display: inline-flex; align-items: center; gap: 7px; margin-top: 16px; font-size: 13.5px; font-weight: 700; color: var(--accent); opacity: 0; transform: translateX(-6px); transition: all .3s; }
    .feature-card:hover .learn { opacity: 1; transform: none; }

    /* Empathy split */
    .empathy-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 24px; }
    .empathy-col { padding: 36px 32px; }
    .empathy-col.old { background: var(--surface); }
    .empathy-col.new { border-color: var(--accent-line); box-shadow: 0 0 60px -20px var(--accent-glow); position: relative; overflow: hidden; }
    .empathy-col.new::before { content:""; position: absolute; inset: 0; background: radial-gradient(80% 60% at 80% 0%, var(--accent-soft), transparent 70%); pointer-events: none; }
    .empathy-tag { display: inline-flex; align-items: center; gap: 8px; font-size: 13px; font-weight: 700; padding: 6px 13px; border-radius: 999px; margin-bottom: 22px; }
    .empathy-col.old .empathy-tag { background: var(--surface-2); color: var(--text-mute); border: 1px solid var(--border-2); }
    .empathy-col.new .empathy-tag { background: var(--accent-soft); color: var(--accent); border: 1px solid var(--accent-line); }
    .empathy-col h3 { font-size: 23px; margin-bottom: 22px; position: relative; }
    .empathy-list { list-style: none; display: flex; flex-direction: column; gap: 16px; position: relative; }
    .empathy-list li { display: flex; gap: 13px; font-size: 15px; color: var(--text-dim); }
    .empathy-list li i { margin-top: 3px; flex: none; }
    .empathy-col.old li i { color: var(--danger); }
    .empathy-col.new li i { color: var(--success); }
    .empathy-col.new li b { color: var(--text); font-weight: 600; }

    /* Interactive demo (POS simulator) */
    .demo-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 36px; align-items: start; }
    .menu-selector { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-top: 26px; }
    .menu-item-btn {
      text-align: left; padding: 16px 17px; border-radius: 15px; background: var(--surface-2);
      border: 1px solid var(--border-2); color: var(--text); transition: all .2s; position: relative; overflow: hidden;
    }
    .menu-item-btn:hover { border-color: var(--accent-line); transform: translateY(-3px); box-shadow: 0 14px 30px -16px var(--accent-glow); }
    .menu-item-btn::before { content: ""; position: absolute; left: 0; top: 0; bottom: 0; width: 3px; background: var(--cc, var(--accent)); opacity: .9; }
    .menu-item-btn .mtop { display: flex; align-items: center; gap: 8px; margin-bottom: 11px; }
    .menu-item-btn .mveg { width: 15px; height: 15px; border-radius: 3px; background: var(--surface-solid); border: 1.5px solid var(--success); display: grid; place-items: center; flex: none; }
    .menu-item-btn .mveg::after { content: ""; width: 6.5px; height: 6.5px; border-radius: 50%; background: var(--success); }
    .menu-item-btn .mcat { font-size: 9.5px; font-weight: 700; letter-spacing: .13em; text-transform: uppercase; color: var(--cc, var(--accent)); }
    [data-theme="light"] .menu-item-btn .mcat { color: color-mix(in srgb, var(--cc, var(--accent)) 58%, #000); }
    .menu-item-name { font-weight: 700; font-size: 15px; font-family: "Plus Jakarta Sans"; }
    .menu-item-price { font-size: 13.5px; color: var(--text-mute); margin-top: 2px; }
    .menu-item-btn .add { position: absolute; top: 14px; right: 14px; width: 26px; height: 26px; border-radius: 8px; background: var(--accent-soft); color: var(--accent); display: grid; place-items: center; font-size: 12px; opacity: 0; transition: opacity .2s; }
    .menu-item-btn:hover .add { opacity: 1; }

    .terminal { padding: 0; overflow: hidden; display: flex; flex-direction: column; min-height: 460px; }
    .terminal-header { padding: 18px 22px; border-bottom: 1px solid var(--border); display: flex; align-items: center; justify-content: space-between; }
    .terminal-header .th-title { font-family: "Plus Jakarta Sans"; font-weight: 700; font-size: 15px; }
    .terminal-body { padding: 22px; flex: 1; display: flex; flex-direction: column; }
    .empty-cart-msg { margin: auto; text-align: center; color: var(--text-mute); font-size: 14.5px; line-height: 1.7; }
    .empty-cart-msg i { font-size: 30px; display: block; margin-bottom: 14px; opacity: .5; }
    .receipt-list { display: flex; flex-direction: column; gap: 4px; margin-bottom: 8px; max-height: 230px; overflow-y: auto; }
    .receipt-row { display: flex; justify-content: space-between; align-items: center; padding: 11px 0; border-bottom: 1px solid var(--border); }
    .receipt-row:last-child { border-bottom: 0; }
    .receipt-row .ri-name { font-weight: 600; font-size: 14.5px; }
    .receipt-row .ri-meta { font-size: 12.5px; color: var(--text-mute); display: flex; align-items: center; gap: 8px; margin-top: 3px; }
    .qty-btn { width: 22px; height: 22px; border-radius: 7px; background: var(--surface-2); border: 1px solid var(--border-2); color: var(--text-dim); display: grid; place-items: center; font-size: 11px; }
    .qty-btn:hover { color: var(--accent); border-color: var(--accent-line); }
    .receipt-row .ri-amt { font-weight: 700; font-variant-numeric: tabular-nums; }
    .receipt-summary { margin-top: auto; padding-top: 14px; }
    .sum-row { display: flex; justify-content: space-between; font-size: 13.5px; color: var(--text-dim); padding: 4px 0; }
    .sum-total { display: flex; justify-content: space-between; font-family: "Plus Jakarta Sans"; font-weight: 800; font-size: 20px; padding-top: 12px; margin-top: 6px; border-top: 1px dashed var(--border-strong); }
    .sandbox-actions { margin-top: 16px; padding-top: 16px; border-top: 1px solid var(--border); display: flex; flex-direction: column; gap: 10px; }
    .sandbox-phone-row { display: flex; gap: 8px; }
    .sandbox-prefix { display: grid; place-items: center; padding: 0 14px; border-radius: 11px; background: var(--surface-2); border: 1px solid var(--border-2); font-weight: 700; font-size: 14px; }

    /* Comparison table */
    .compare-wrap { max-width: 920px; margin: 0 auto; overflow: hidden; padding: 8px; }
    .compare-table { width: 100%; border-collapse: collapse; }
    .compare-table th, .compare-table td { padding: 18px 22px; text-align: left; font-size: 14.5px; border-bottom: 1px solid var(--border); }
    .compare-table thead th { font-family: "Plus Jakarta Sans"; font-size: 14px; color: var(--text-mute); font-weight: 700; }
    .compare-table thead th.us { color: var(--accent); }
    .compare-table tbody td:first-child { font-weight: 600; color: var(--text); }
    .compare-table .us-col { background: var(--accent-soft); font-weight: 600; color: var(--text); }
    .compare-table tr:last-child td { border-bottom: 0; }
    .compare-table .us-col i { color: var(--accent); margin-right: 7px; }
    .compare-table td.other { color: var(--text-mute); }

    /* Pricing */
    .pricing-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 22px; align-items: stretch; }
    .pricing-card { padding: 32px 28px; display: flex; flex-direction: column; transition: transform .3s, box-shadow .3s; }
    .pricing-card:hover { transform: translateY(-6px); }
    .pricing-card.featured { border-color: var(--accent-line); box-shadow: 0 0 70px -24px var(--accent-glow); position: relative; }
    .pricing-card.featured::after { content: "Most Popular"; position: absolute; top: 22px; right: 24px; font-size: 11px; font-weight: 800; letter-spacing: .04em; text-transform: uppercase; color: var(--on-accent); background: var(--accent); padding: 5px 12px; border-radius: 999px; }
    .tier-name { font-family: "Plus Jakarta Sans"; font-size: 14px; font-weight: 700; color: var(--accent); letter-spacing: .04em; text-transform: uppercase; margin-bottom: 8px; }
    .tier-desc { font-size: 13.5px; color: var(--text-dim); margin-bottom: 22px; min-height: 40px; }
    .tier-price { display: flex; align-items: baseline; gap: 6px; margin-bottom: 24px; }
    .tier-price .amt { font-family: "Plus Jakarta Sans"; font-size: 44px; font-weight: 800; letter-spacing: -.03em; }
    .tier-price .per { font-size: 14px; color: var(--text-mute); }
    .tier-feats { list-style: none; display: flex; flex-direction: column; gap: 12px; margin-bottom: 28px; flex: 1; }
    .tier-feats li { display: flex; gap: 11px; font-size: 14px; color: var(--text-dim); }
    .tier-feats li i { color: var(--accent); margin-top: 3px; flex: none; font-size: 12px; }

    /* Testimonials */
    .testi-carousel { position: relative; overflow: hidden; }
    .testi-track { display: flex; transition: transform .5s cubic-bezier(.2,.9,.3,1); }
    .testi-card { flex: 0 0 100%; padding: 8px; }
    .testi-inner { padding: 44px 48px; text-align: center; max-width: 820px; margin: 0 auto; }
    .testi-stars { color: var(--accent); font-size: 16px; margin-bottom: 22px; letter-spacing: 3px; }
    .testi-quote { font-family: "Plus Jakarta Sans"; font-size: clamp(20px, 2.6vw, 28px); font-weight: 600; line-height: 1.4; letter-spacing: -.02em; margin-bottom: 28px; }
    .testi-author { display: flex; align-items: center; justify-content: center; gap: 14px; }
    .testi-avatar { width: 50px; height: 50px; border-radius: 50%; background: linear-gradient(135deg, var(--accent), #ff8a3d); display: grid; place-items: center; font-weight: 800; color: #fff; font-family: "Plus Jakarta Sans"; font-size: 18px; }
    .testi-meta .n { font-weight: 700; font-size: 15px; }
    .testi-meta .r { font-size: 13px; color: var(--text-mute); }
    .testi-nav { display: flex; align-items: center; justify-content: center; gap: 16px; margin-top: 30px; }
    .testi-dots { display: flex; gap: 8px; }
    .testi-dots button { width: 8px; height: 8px; border-radius: 999px; border: 0; background: var(--border-strong); transition: all .3s; }
    .testi-dots button.active { width: 24px; background: var(--accent); }

    /* CTA + Footer */
    .cta-band { padding: 70px; text-align: center; position: relative; overflow: hidden; border-color: var(--accent-line); }
    .cta-band::before { content:""; position: absolute; inset: 0; background: radial-gradient(60% 120% at 50% 0%, var(--accent-soft), transparent 70%); pointer-events: none; }
    .cta-band h2 { font-size: clamp(30px, 4vw, 48px); margin-bottom: 16px; position: relative; }
    .cta-band p { font-size: 18px; color: var(--text-dim); margin-bottom: 32px; position: relative; }
    .cta-actions { display: flex; gap: 14px; justify-content: center; flex-wrap: wrap; position: relative; }

    .site-footer { padding: 70px 0 40px; border-top: 1px solid var(--border); margin-top: 60px; position: relative; z-index: 1; }
    .footer-grid { display: grid; grid-template-columns: 1.4fr 1fr 1fr 1fr; gap: 40px; margin-bottom: 50px; }
    .footer-brand p { font-size: 14px; color: var(--text-dim); margin: 18px 0; max-width: 280px; }
    .footer-social { display: flex; gap: 10px; }
    .footer-col h5 { font-family: "Plus Jakarta Sans"; font-size: 13px; text-transform: uppercase; letter-spacing: .1em; color: var(--text-mute); margin-bottom: 16px; }
    .footer-col a { display: block; font-size: 14px; color: var(--text-dim); padding: 6px 0; transition: color .2s; }
    .footer-col a:hover { color: var(--accent); }
    .footer-bottom { display: flex; justify-content: space-between; align-items: center; padding-top: 28px; border-top: 1px solid var(--border); flex-wrap: wrap; gap: 14px; }
    .footer-bottom .legal { display: flex; gap: 22px; }
    .footer-bottom .legal a { font-size: 13px; color: var(--text-mute); }
    .footer-bottom .legal a:hover { color: var(--text-dim); }
    .footer-bottom .cr { font-size: 13px; color: var(--text-mute); }

    /* Modal */
    .modal-overlay { position: fixed; inset: 0; background: rgba(0,0,0,.6); backdrop-filter: blur(8px); display: none; align-items: center; justify-content: center; z-index: 2000; padding: 24px; }
    .modal-overlay.show { display: flex; animation: fadeUp .3s; }
    .modal-card { max-width: 440px; width: 100%; padding: 36px; text-align: center; }
    .modal-icon { width: 64px; height: 64px; border-radius: 18px; background: var(--success-soft); color: var(--success); display: grid; place-items: center; font-size: 28px; margin: 0 auto 20px; }
    .modal-card h3 { font-size: 22px; margin-bottom: 10px; }
    .modal-card p { font-size: 15px; color: var(--text-dim); margin-bottom: 26px; }

    .mobile-menu-btn { display: none; }

    @media (max-width: 980px) {
      .hero-grid { grid-template-columns: 1fr; gap: 40px; }
      .features-grid { grid-template-columns: repeat(2, 1fr); }
      .empathy-grid, .demo-grid, .pricing-grid { grid-template-columns: 1fr; }
      .pricing-card.featured { order: -1; }
      .footer-grid { grid-template-columns: 1fr 1fr; gap: 30px; }
    }
    @media (max-width: 640px) {
      .nav-links { display: none; }
      .link-signin {
        padding: 8px 10px;
        font-size: 13.5px;
      }
      .theme-toggle {
        width: 36px;
        height: 36px;
      }
      .nav-cta-group {
        gap: 8px;
      }
      .container {
        width: min(1240px, calc(100% - 32px));
      }
      .features-grid { grid-template-columns: 1fr; }
      .menu-selector { grid-template-columns: 1fr 1fr; }
      .hero { padding: 120px 0 60px; }
      .cta-band { padding: 44px 26px; }
      .compare-table th, .compare-table td { padding: 13px 12px; font-size: 13px; }
      .footer-grid { grid-template-columns: 1fr; }
    }
  </style>
</head>
